options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
// Captura o elemento HTML onde o valor será exibido
const htmlgraphicsValue = htmlNode.getElementById('htmlgraphics-value');

if (htmlgraphicsValue) {
  // Verifica se há dados na resposta
  if (data && data.series && data.series.length > 0) {
    // Recupera o valor da primeira série
    const valueField = data.series[0].fields[1]; // Assumindo que o valor está no primeiro campo da série

    if (valueField) {
      // Exibe o valor no elemento HTML
      const valueInSeconds = valueField.values.get(valueField.values.length - 1);

      // Converte o uptime para o formato desejado
      let seconds = valueInSeconds;
      let days = Math.floor(seconds / (24 * 60 * 60));
      seconds -= days * 24 * 60 * 60;
      let hrs = Math.floor(seconds / 3600);
      seconds -= hrs * 3600;
      let mnts = Math.floor(seconds / 60);
      seconds -= mnts * 60;

      // Formata para sempre ter dois dígitos
      let formattedHrs = String(hrs).padStart(2, '0');
      let formattedMnts = String(mnts).padStart(2, '0');
      let formattedSeconds = String(seconds).padStart(2, '0');

      uptimeInSeconds = `${days} d ${formattedHrs}:${formattedMnts}:${formattedSeconds}`;

      htmlgraphicsValue.innerHTML = `
      <div style="
  display: flex;
  justify-content: space-between;
  align-items: center;
  height: 27px; /* Altura ajustável */
  background: url('https://static.wixstatic.com/media/c319a6_fd2ffebb0736449d9265be8744b3ba78~mv2.webp');
  background-size: cover; /* Cobrir todo o elemento */
  background-repeat: no-repeat;
  background-position: center;
  padding: 31px; /* Padding para ajustar o espaço interno */
  border-radius: 100px; /* Border-radius para uma aparência mais arredondada */
  width: auto; /* Largura ajustável */
">
   <div style="margin-right: 10px;">
      <img src="https://upload.wikimedia.org/wikipedia/commons/thumb/6/6f/Zabbix_logo.svg/2560px-Zabbix_logo.svg.png" width="150px" style="margin-right: 0px;" />
    </div>
    <div style="flex-grow: 1; text-align: center;">
      <span style="color:#ffffff; font-size: 35px; font-weight: bold; font-family: Arial, sans-serif; vertical-align: middle;">Monitoramento - BGP</span>
</div>
<div class="box" style="
  background: linear-gradient(to right, #3BAFAA, #1E8C93); /* Cor de fundo verde */
  padding: 8px; /* Espaçamento interno */
  border-radius: 20px; /* Ajuste para tornar o elemento um retângulo com cantos arredondados */
  width: 210px; /* Largura do retângulo */
  height: 37px; /* Altura do retângulo */
  display: flex;
  justify-content: center;
  align-items: center;

">
  <span style="color: white; font-weight: ; font-size: 17px;">Uptime ${uptimeInSeconds}</span>
</div>
      `;
    } else {
      htmlgraphicsValue.textContent = "No data";
    }
  } else {
    htmlgraphicsValue.textContent = "No data";
  }
}

options.rootCSS:
html, body {
  height: 100%;
  margin: 0;
  padding: 0;
  font-family: 'Segoe UI', sans-serif;
  background: linear-gradient(135deg, #1d3946 0%, #121c2d 100%);
  backdrop-filter: blur(8px);
  color: #ffffff;
  box-sizing: border-box;
}

/* Painéis com efeito vidro na versão 11 */
div[class*="-panel-content"][data-testid*="panel content"] {
  background: rgba(10, 45, 59, 0.801) !important;
  border: 1px solid rgba(86, 213, 220, 0.2);
  border-radius: 6px;
  backdrop-filter: blur(10px);
  box-shadow: 0 0 8px rgba(0, 255, 255, 0.02);
  overflow: hidden;
  transition: all 0.3s ease-in-out;
  will-change: box-shadow, border-color;
}

/* Hover com destaque */
div[class*="-panel-content"][data-testid*="panel content"]:hover {
  box-shadow: 0 0 25px rgba(0, 255, 255, 0.15);
  border-color: rgba(0, 255, 255, 0.2);
}

options.css:
/* =========================
   ISPX Sea-Glass+ — Otimizado (HTML Graphics)
   - Menos repetição
   - Menor especificidade (where)
   - Mantém: scroll, paginação, tooltip, widths fix
   ========================= */

#ispx-root, #ispx-root *{ box-sizing:border-box; }

#ispx-root{
  font-family: Inter, system-ui, -apple-system, "Segoe UI", Roboto, Arial, sans-serif;
  color: rgba(255,255,255,.92);

  /* paleta */
  --bg0:#050A14;
  --bg1: rgba(15, 25, 40, .55);
  --bg2: rgba(10, 18, 32, .72);

  --stroke:  rgba(110,200,255,.18);
  --stroke2: rgba(110,200,255,.12);

  --pri:#2BD9C7;
  --pri2:#22B3C2;

  --good:#22C55E;
  --warn:#F59E0B;
  --bad:#EF4444;

  --txt: rgba(255,255,255,.92);
  --muted: rgba(255,255,255,.65);

  --r12:12px;
  --r16:16px;

  --shadow:  0 10px 26px rgba(0,0,0,.35);
  --shadow2: 0  8px 20px rgba(0,0,0,.28);

  /* altura máxima da tabela (pode ajustar no painel) */
  --tableMax: calc(100vh - 260px);

  /* FORCE HEIGHT CHAIN */
  height:100% !important;
  min-height:0 !important;
}

/* ========= layout ========= */
#ispx-root :where(.u-wrap){
  padding:10px;
  background:
    radial-gradient(1000px 500px at 20% 0%, rgba(43,217,199,.16), transparent 60%),
    radial-gradient(900px 500px at 80% 0%, rgba(34,179,194,.12), transparent 60%);

  height:100% !important;
  min-height:0 !important;
  display:flex !important;
  flex-direction:column !important;
}

#ispx-root :where(.u-head){
  display:flex;
  align-items:flex-end;
  justify-content:space-between;
  gap:12px;
  padding:10px 12px;
  border-radius:var(--r16);
  background:linear-gradient(180deg, rgba(255,255,255,.06), rgba(255,255,255,.02));
  border:1px solid var(--stroke2);
  box-shadow:var(--shadow2);
  flex:0 0 auto !important;
}

#ispx-root :where(.u-title h2){
  margin:0;
  font-size:16px;
  letter-spacing:.2px;
}
#ispx-root :where(.u-title .sub){
  margin-top:3px;
  font-size:12px;
  color:var(--muted);
}

#ispx-root :where(.u-meta){ display:flex; gap:8px; flex-wrap:wrap; }
#ispx-root :where(.u-chip){
  padding:6px 10px;
  border-radius:999px;
  background:rgba(0,0,0,.35);
  border:1px solid var(--stroke2);
  color:rgba(255,255,255,.85);
  font-size:12px;
}

#ispx-root :where(.u-grid){
  margin-top:10px;
  display:grid;
  grid-template-columns:360px 1fr;
  gap:10px;

  flex:1 1 auto !important;
  min-height:0 !important;
}

/* ========= left ========= */
#ispx-root :where(.u-left){
  display:flex;
  flex-direction:column;
  gap:10px;
  min-height:0 !important;
}

#ispx-root :where(.u-box){
  border-radius:var(--r16);
  border:1px solid var(--stroke2);
  background:linear-gradient(180deg, rgba(255,255,255,.05), rgba(255,255,255,.02));
  box-shadow:var(--shadow2);
  padding:10px;
}

#ispx-root :where(.u-box .u-box-title){
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:10px;
  margin-bottom:8px;
}
#ispx-root :where(.u-box .u-box-title .t){
  font-weight:700;
  font-size:12px;
  letter-spacing:.25px;
  color:rgba(255,255,255,.86);
}
#ispx-root :where(.u-box .u-box-title .hint){
  font-size:11px;
  color:var(--muted);
}

#ispx-root :where(.u-kpis){
  display:grid;
  grid-template-columns:1fr 1fr;
  gap:8px;
}
#ispx-root :where(.u-kpi){
  padding:10px;
  border-radius:var(--r12);
  background:rgba(0,0,0,.32);
  border:1px solid var(--stroke2);
  box-shadow:0 6px 16px rgba(0,0,0,.22);
}
#ispx-root :where(.u-kpi .l){ font-size:11px; color:var(--muted); }
#ispx-root :where(.u-kpi .v){ font-size:16px; font-weight:800; margin-top:4px; }

#ispx-root :where(.u-kpi.good .v){ color:var(--good); }
#ispx-root :where(.u-kpi.warn .v){ color:var(--warn); }
#ispx-root :where(.u-kpi.bad  .v){ color:var(--bad); }
#ispx-root :where(.u-kpi.pri  .v){ color:var(--pri); }

#ispx-root :where(.u-vrfs){ display:flex; flex-wrap:wrap; gap:6px; }
#ispx-root :where(.u-pill){
  padding:6px 10px;
  border-radius:999px;
  font-size:12px;
  cursor:pointer;
  user-select:none;
  border:1px solid var(--stroke2);
  background:rgba(0,0,0,.30);
  color:rgba(255,255,255,.84);
}
#ispx-root :where(.u-pill.on){
  border-color:rgba(43,217,199,.45);
  background:rgba(43,217,199,.12);
}

/* ========= top ========= */
#ispx-root :where(.u-tabs){ display:flex; gap:6px; flex-wrap:wrap; }
#ispx-root :where(.u-tabs button){
  padding:6px 10px;
  border-radius:999px;
  border:1px solid var(--stroke2);
  background:rgba(0,0,0,.26);
  color:rgba(255,255,255,.82);
  cursor:pointer;
}
#ispx-root :where(.u-tabs button.on){
  border-color:rgba(43,217,199,.50);
  background:rgba(43,217,199,.12);
}

#ispx-root :where(.u-top){ width:100%; border-collapse:collapse; }
#ispx-root :where(.u-top th, .u-top td){
  padding:8px;
  border-bottom:1px solid rgba(255,255,255,.06);
  font-size:12px;
}
#ispx-root :where(.u-top th){ text-align:left; color:var(--muted); font-weight:700; }
#ispx-root :where(.u-top td b){ color:rgba(255,255,255,.92); }

/* ========= botão histórico ========= */
#ispx-root :where(.u-hbtn){
  padding:6px 8px;
  border-radius:10px;
  border:1px solid rgba(110,200,255,.16);
  background:rgba(0,0,0,.30);
  color:rgba(255,255,255,.85);
  cursor:pointer;
  font-size:12px;
  line-height:1;
}
#ispx-root :where(.u-hbtn:hover){
  background:rgba(43,217,199,.10);
  border-color:rgba(43,217,199,.35);
}

/* ========= right ========= */
#ispx-root :where(.u-right){
  display:flex;
  flex-direction:column;
  min-height:0 !important;
  gap:10px;
}

#ispx-root :where(.u-search){
  display:flex;
  gap:10px;
  align-items:center;
  justify-content:space-between;
  padding:10px 12px;
  border-radius:var(--r16);
  border:1px solid var(--stroke2);
  background:linear-gradient(180deg, rgba(255,255,255,.05), rgba(255,255,255,.02));
  box-shadow:var(--shadow2);

  flex:0 0 auto !important;
}
#ispx-root :where(.u-search input){
  width:100%;
  padding:10px 12px;
  border-radius:12px;
  border:1px solid rgba(110,200,255,.16);
  background:rgba(0,0,0,.35);
  color:rgba(255,255,255,.92);
  outline:none;
}
#ispx-root :where(.u-search .count){
  font-size:12px;
  color:var(--muted);
  white-space:nowrap;
}

/* scroll wrapper */
#ispx-root :where(.u-table-scroll){
  border-radius:var(--r16);
  border:1px solid var(--stroke2);
  background:linear-gradient(180deg, rgba(255,255,255,.05), rgba(255,255,255,.02));
  box-shadow:var(--shadow2);

  flex:1 1 auto !important;
  min-height:0 !important;
  overflow:auto !important;
  scrollbar-gutter:stable;
  max-height:var(--tableMax) !important;
}

/* ========= table ========= */
#ispx-root :where(.u-table){
  width:100%;
  border-collapse:collapse;
}
#ispx-root :where(.u-table thead th){
  position:sticky;
  top:0;
  z-index:2;
  background:rgba(0,0,0,.62);
  border-bottom:1px solid rgba(255,255,255,.08);

  font-size:12px;
  text-align:left;
  padding:10px 10px;
  color:rgba(255,255,255,.70);
  font-weight:800;
}

#ispx-root :where(.u-table td){
  padding:10px 10px;
  border-bottom:1px solid rgba(255,255,255,.06);
  font-size:12px;
  color:rgba(255,255,255,.86);
}
#ispx-root :where(.u-table tr:hover td){ background:rgba(43,217,199,.06); }
#ispx-root :where(.u-table .center){ text-align:center; }
#ispx-root :where(.u-table td.client){ font-weight:800; }

/* ========= sort ========= */
#ispx-root :where(.u-table thead th.sortable){
  cursor:pointer;
  user-select:none;
}
#ispx-root :where(.u-table thead th.sortable:hover){ color:rgba(255,255,255,.86); }

#ispx-root :where(.u-table thead th.sortable::after){
  content:"";
  display:inline-block;
  margin-left:6px;
  opacity:.55;
  transform:translateY(-1px);
}
#ispx-root :where(.u-table thead th.sort-asc::after){ content:"▲"; opacity:.75; }
#ispx-root :where(.u-table thead th.sort-desc::after){ content:"▼"; opacity:.75; }

/* pills */
#ispx-root :where(.pill){
  display:inline-flex;
  align-items:center;
  justify-content:center;
  min-width:34px;
  padding:4px 10px;
  border-radius:999px;
  font-size:12px;
  border:1px solid rgba(255,255,255,.10);
  background:rgba(0,0,0,.28);
}
#ispx-root :where(.pill.pri){  color:var(--pri);  border-color:rgba(43,217,199,.30); background:rgba(43,217,199,.10); }
#ispx-root :where(.pill.good){ color:var(--good); border-color:rgba(34,197,94,.28); background:rgba(34,197,94,.10); }
#ispx-root :where(.pill.warn){ color:var(--warn); border-color:rgba(245,158,11,.28); background:rgba(245,158,11,.10); }
#ispx-root :where(.pill.bad){  color:var(--bad);  border-color:rgba(239,68,68,.28);  background:rgba(239,68,68,.10); }

/* expand button */
#ispx-root :where(.u-exp){
  width:34px;
  height:28px;
  border-radius:10px;
  border:1px solid rgba(110,200,255,.16);
  background:rgba(0,0,0,.30);
  color:rgba(255,255,255,.85);
  cursor:pointer;
}
#ispx-root :where(.u-exp .arrow){
  display:inline-block;
  transition:transform .18s ease;
}
#ispx-root :where(.u-exp[aria-expanded="true"] .arrow){ transform:rotate(90deg); }

/* child row */
#ispx-root :where(.u-child){ display:none; }
#ispx-root :where(.child-wrap){
  padding:10px;
  border-radius:var(--r12);
  background:rgba(0,0,0,.25);
  border:1px solid rgba(110,200,255,.10);
}
#ispx-root :where(.u-mini-sub){
  width:100%;
  border-collapse:collapse;
}
#ispx-root :where(.u-mini-sub th, .u-mini-sub td){
  padding:8px;
  border-bottom:1px solid rgba(255,255,255,.06);
  font-size:12px;
}
#ispx-root :where(.u-mini-sub th){
  color:rgba(255,255,255,.65);
  text-align:left;
  font-weight:800;
}

/* modal */
#ispx-root :where(.u-modal){
  position:fixed;
  inset:0;
  background:rgba(0,0,0,.5);
  display:none;
  align-items:center;
  justify-content:center;
  padding:20px;
  z-index:9999;
}
#ispx-root :where(.u-modal.on){
  display:flex;
}
#ispx-root :where(.u-modal .box){
  width:min(900px, 96vw);
  border-radius:var(--r16);
  border:1px solid var(--stroke2);
  background:rgba(10,18,32,.92);
  box-shadow:var(--shadow);
}
#ispx-root :where(.u-modal .head){
  display:flex;
  justify-content:space-between;
  align-items:center;
  padding:12px 14px;
  border-bottom:1px solid rgba(255,255,255,.08);
}
#ispx-root :where(.u-modal .head .t){ font-weight:900; }
#ispx-root :where(.u-modal .head button){
  padding:8px 10px;
  border-radius:10px;
  border:1px solid rgba(110,200,255,.16);
  background:rgba(0,0,0,.30);
  color:rgba(255,255,255,.86);
  cursor:pointer;
}
#ispx-root :where(.u-modal .content){ padding:14px; }

/* responsivo */
@media (max-width:1100px){
  #ispx-root :where(.u-grid){ grid-template-columns:1fr; }
}

/* ==========================================
   PAGINAÇÃO
   ========================================== */
#ispx-root :where(.u-pagination){
  display:flex;
  align-items:center;
  justify-content:space-between;
  gap:10px;
  padding:10px 12px;
  border-radius:var(--r16);
  border:1px solid var(--stroke2);
  background:linear-gradient(180deg, rgba(255,255,255,.05), rgba(255,255,255,.02));
  box-shadow:var(--shadow2);
}
#ispx-root :where(.u-pagination .left, .u-pagination .right){
  display:flex;
  align-items:center;
  gap:8px;
}
#ispx-root :where(.u-pagination button){
  padding:8px 10px;
  border-radius:10px;
  border:1px solid rgba(110,200,255,.16);
  background:rgba(0,0,0,.30);
  color:rgba(255,255,255,.86);
  cursor:pointer;
}
#ispx-root :where(.u-pagination button:disabled){
  opacity:.45;
  cursor:not-allowed;
}
#ispx-root :where(.u-pagination .info){
  font-size:12px;
  color:var(--muted);
  white-space:nowrap;
}
#ispx-root :where(.u-pagination select){
  padding:8px 10px;
  border-radius:10px;
  border:1px solid rgba(110,200,255,.16);
  background:rgba(0,0,0,.30);
  color:rgba(255,255,255,.86);
  outline:none;
}

/* ==========================================
   LAST ERROR — tooltip flutuante
   Requer ONRENDER com .le-help + data-tip
   ========================================== */
#ispx-root :where(.le-wrap){
  display:flex;
  align-items:center;
  gap:8px;
}

#ispx-root :where(.le-help){
  position:relative;
  display:inline-flex;
  align-items:center;
  justify-content:center;
  width:18px;
  height:18px;
  border-radius:999px;
  border:1px solid rgba(110,200,255,.22);
  background:rgba(0,0,0,.28);
  color:rgba(255,255,255,.82);
  font-weight:900;
  font-size:12px;
  line-height:1;
  cursor:help;
  user-select:none;
  pointer-events:auto;
}

/* Desliga tooltip antigo CSS-only */
#ispx-root :where(.le-help::after, .le-help::before){ display:none !important; }

/* Tooltip global (injetado no <body> pelo JS) */
.le-float-tip{
  position:fixed;
  z-index:999999;
  max-width:min(440px, 72vw);
  padding:10px 12px;
  border-radius:12px;
  border:1px solid rgba(110,200,255,.18);
  background:rgba(10,18,32,.96);
  box-shadow:0 12px 26px rgba(0,0,0,.38);
  color:rgba(255,255,255,.92);
  font-size:12px;
  line-height:1.25;
  pointer-events:none;
  opacity:0;
  transform:translateY(4px);
  transition:opacity .08s ease, transform .08s ease;
}
.le-float-tip.is-on{ opacity:1; transform:translateY(0); }

.le-float-arrow{
  position:fixed;
  z-index:999999;
  width:10px;
  height:10px;
  background:rgba(10,18,32,.96);
  border-left:1px solid rgba(110,200,255,.18);
  border-top:1px solid rgba(110,200,255,.18);
  transform:rotate(45deg);
  pointer-events:none;
  opacity:0;
  transition:opacity .08s ease;
}
.le-float-arrow.is-on{ opacity:1; }

/* =========================================================
   FIX WIDTHS — sobrescreve inline widths
   ========================================================= */

/* layout fixo pra respeitar widths */
#ispx-root :where(table.u-table, table.u-mini-sub){
  table-layout:fixed !important;
  width:100% !important;
}

/* ---------- TABELA PRINCIPAL ----------
   1 CLIENTE, 2 ASN, 3 HOST, 4 SESSÕES, 5 UP, 6 ALERT, 7 0PFX, 8 AÇÃO
*/
#ispx-root :where(table.u-table thead th[data-col="client"], table.u-table tbody td:nth-child(1)){ width:38% !important; }
#ispx-root :where(table.u-table thead th[data-col="asn"],    table.u-table tbody td:nth-child(2)){ width:10% !important; }
#ispx-root :where(table.u-table thead th[data-col="host"],   table.u-table tbody td:nth-child(3)){ width:18% !important; }
#ispx-root :where(table.u-table thead th[data-col="sessions"],table.u-table tbody td:nth-child(4)){ width: 9% !important; }
#ispx-root :where(table.u-table thead th[data-col="up"],     table.u-table tbody td:nth-child(5)){ width: 7% !important; }
#ispx-root :where(table.u-table thead th[data-col="alert"],  table.u-table tbody td:nth-child(6)){ width: 7% !important; }
#ispx-root :where(table.u-table thead th[data-col="nopfx"],  table.u-table tbody td:nth-child(7)){ width: 7% !important; }
#ispx-root :where(table.u-table thead th:not([data-col]),    table.u-table tbody td:nth-child(8)){ width: 4% !important; }

#ispx-root :where(table.u-table tbody td:nth-child(1)){
  white-space:nowrap;
  overflow:hidden;
  text-overflow:ellipsis;
}

/* ---------- MINI TABELA (expand) ----------
   1 IPVER, 2 VRF, 3 PEER, 4 STATUS, 5 UPTIME, 6 TOTAL PREFIX, 7 LAST ERROR, 8 HIST
*/
#ispx-root :where(table.u-mini-sub thead th:nth-child(1), table.u-mini-sub tbody td:nth-child(1)){ width: 7% !important; }
#ispx-root :where(table.u-mini-sub thead th:nth-child(2), table.u-mini-sub tbody td:nth-child(2)){ width:11% !important; }
