options.onInit:
// Sets the text from customProperties
const htmlgraphicsText = htmlNode.getElementById('htmlgraphics-text');

if (htmlgraphicsText) {
  htmlgraphicsText.textContent = customProperties.text;

  // Change the text color based on the theme
  if (theme.isDark) {
    htmlgraphicsText.style.color = 'green';
  } else {
    htmlgraphicsText.style.color = 'red';
  }
}

options.onRender:
(() => {
  try {
    const root = htmlNode;
    if (!root) return;

    const q  = (sel) => root.querySelector(sel);
    const qa = (sel) => Array.from(root.querySelectorAll(sel));
    const setText = (sel, v) => { const el = q(sel); if (el) el.textContent = v; };

    // ========= helpers =========
    const safeStr = (v) => (v === null || v === undefined) ? "" : String(v);
    const toNum = (v) => {
      const n = Number(v);
      return Number.isFinite(n) ? n : 0;
    };
    function fmtPrefixes(n) {
  if (!Number.isFinite(n)) return "0";
  if (n >= 1e9) return (n / 1e9).toFixed(2).replace(/\.0+$/, "") + "B";
  if (n >= 1e6) return (n / 1e6).toFixed(2).replace(/\.0+$/, "") + "M";
  if (n >= 1e3) return (n / 1e3).toFixed(2).replace(/\.0+$/, "") + "K";
  return String(n);
}

    const esc = (s) => safeStr(s)
      .replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;")
      .replaceAll('"',"&quot;").replaceAll("'","&#39;");

    // ========= time normalize =========
    function normTs(v){
      try {
        if (v === null || v === undefined) return null;

        if (v instanceof Date) {
          const t = v.getTime();
          return Number.isFinite(t) ? t : null;
        }

        if (typeof v === "string") {
          const s = v.trim();
          if (!s) return null;

          const n = Number(s);
          if (Number.isFinite(n)) return normTs(n);

          const p = Date.parse(s);
          return Number.isFinite(p) ? p : null;
        }

        let n = Number(v);
        if (!Number.isFinite(n)) return null;

        if (n >= 1e17) return Math.round(n / 1e6);   // ns -> ms
        if (n >= 1e14) return Math.round(n / 1e3);   // us -> ms
        if (n >= 1e11) return Math.round(n);         // ms
        return Math.round(n * 1000);                 // s -> ms
      } catch (e) {
        return null;
      }
    }

    // ========= LAST ERROR tooltip (leve) =========
    const normErr = (s) => safeStr(s).toLowerCase().replace(/\s+/g, " ").trim();
    function explainLastError(raw){
      const t = normErr(raw);
      if (!t || t === "-") return "";
      if (t.includes("hold timer expired")){
        return "Hold Timer Expired: o peer parou de enviar keepalive/updates dentro do tempo. Normalmente indica perda de link, latência/jitter, CPU alta, ACL/policing ou MTU.";
      }
      if (t.includes("cease") && t.includes("subcode 02")){
        return "Cease (subcode 02): encerramento administrativo. Geralmente manutenção, reset manual ou alteração de configuração no peer.";
      }
      if (t.includes("cease") && t.includes("subcode 03")){
        return "Cease (subcode 03): peer removido/alterado (deconfig). Ex.: neighbor deletado, troca de VRF/IP/policy.";
      }
      if (t.includes("finite state machine error")){
        return "Finite State Machine Error: erro interno do processo BGP. Pode ser incompatibilidade/capability, bug de software, ou flap anormal.";
      }
      return "Erro BGP reportado pelo equipamento. Se recorrente, verifique flaps, MTU, estabilidade do link e policies BGP.";
    }

    const fmtUptime = (sec) => {
      const s = toNum(sec);
      if (!s) return "-";
      const d = Math.floor(s / 86400);
      const h = Math.floor((s % 86400) / 3600);
      const m = Math.floor((s % 3600) / 60);
      if (d > 0) return `${d}d ${h}h`;
      if (h > 0) return `${h}h ${m}m`;
      return `${m}m`;
    };

    function getLastValue(ser) {
      const fields = ser?.fields || [];
      const f = fields.find(x => x?.type !== "time") || fields[1] || fields[0];
      if (!f?.values) return null;
      const len = f.values.length ?? 0;
      if (!len) return null;
      return f.values.get ? f.values.get(len - 1) : f.values[len - 1];
    }

    function getLastTimestamp(ser) {
      const fields = ser?.fields || [];
      const tf = fields.find(x => x?.type === "time") || fields.find(x => String(x?.name||"").toLowerCase() === "time");
      if (!tf?.values) return null;
      const len = tf.values.length ?? 0;
      if (!len) return null;
      const v = tf.values.get ? tf.values.get(len - 1) : tf.values[len - 1];
      const ts = normTs(v);
      return ts;
    }

    // ========= time series helpers (FIX: pega field correto do STATE) =========
    function extractTimeValueArrays(ser){
  const fields = ser?.fields || [];

  const tf =
    fields.find(f => f?.type === "time") ||
    fields.find(f => String(f?.name||"").toLowerCase() === "time");

  const nonTime = fields.filter(f => f && f.type !== "time");

  const pickByName = (re) =>
    nonTime.find(f => re.test(String(f?.name||"").toLowerCase()));

  const vf =
    pickByName(/state|bgp.*state/) ||
    pickByName(/^value$| val$|valor/) ||
    nonTime.find(f => f?.type === "number" || f?.type === "numeric") ||
    nonTime[0];

  const rawTimes  = tf?.values?.toArray ? tf.values.toArray() : (tf?.values || []);
  const rawValues = vf?.values?.toArray ? vf.values.toArray() : (vf?.values || []);

  const tArr = Array.isArray(rawTimes) ? rawTimes : [];
  const vArr = Array.isArray(rawValues) ? rawValues : [];

  const L = Math.min(tArr.length, vArr.length);

  const times = [];
  const values = [];

  for (let i = 0; i < L; i++){
    const ts = normTs(tArr[i]);
    const n = Number(vArr[i]);
    times.push(ts);
    values.push(Number.isFinite(n) ? n : NaN);
  }

  return { times, values, valueFieldName: String(vf?.name || "") };
}


    function stateNumToName(n){
      return (n === 0) ? "RESET" :
             (n === 6) ? "ESTABLISHED" :
             (n === 5) ? "OPENCONFIRM" :
             (n === 4) ? "OPENSENT" :
             (n === 3) ? "ACTIVE" :
             (n === 2) ? "CONNECT" :
             (n === 1) ? "IDLE" : `STATE_${n}`;
    }

    function fmtDT(ms){
      const t = normTs(ms);
      if (!t) return "-";
      const d = new Date(t);
      const dd = String(d.getDate()).padStart(2,"0");
      const mm = String(d.getMonth()+1).padStart(2,"0");
      const yy = d.getFullYear();
      const hh = String(d.getHours()).padStart(2,"0");
      const mi = String(d.getMinutes()).padStart(2,"0");
      const ss = String(d.getSeconds()).padStart(2,"0");
      return `${dd}/${mm}/${yy} ${hh}:${mi}:${ss}`;
    }

    function extractHost(ser) {
      for (const f of (ser?.fields || [])) {
        const lb = f?.labels || {};
        const cand = lb.host || lb.hostname || lb.instance || lb.device || lb.node || lb.router;
        if (cand) return String(cand);
      }
      const n = safeStr(ser?.name || "");
      const cut = n.indexOf(":");
      if (cut > -1) {
        const host = n.slice(0, cut).trim();
        if (host) return host;
      }
      return "-";
    }

    // ========= parseName =========
    function parseName(itemName) {
      const s = safeStr(itemName).trim();
      const cut = s.indexOf(":");
      const core = (cut > -1 ? s.slice(cut + 1) : s).trim();

      const re = /^(.+?)\s+v([46])\s*\[([^\]]+)\]\s*\[([^\]]+)\]\s*(.*?)(?:\s*\(AS(\d+)\))?\s*$/i;
      const m = core.match(re);

      if (m) {
        const metricRaw = (m[1] || "").trim();
        const ipver = m[2] ? `IPv${m[2]}` : "-";
        const vrf = (m[3] || "-").trim();
        const peer = (m[4] || "-").trim();
        const client = (m[5] || "-").trim();
        const asn = (m[6] || "").trim();

        const mr = metricRaw.toLowerCase();
        let metric = "other";
        if (mr.includes("state")) metric = "state";
        else if (mr.includes("uptime")) metric = "uptime";
        else if (mr.includes("prefix")) metric = "prefixes";
        else if (mr.includes("error")) metric = "error";

        return { metric, ipver, vrf, peer, client, asn };
      }
      return { metric:"other", ipver:"-", vrf:"-", peer:"-", client:"-", asn:"" };
    }

    // ========= dados =========
    const series = Array.isArray(data?.series) ? data.series : [];
    if (!series.length) {
      const body = q("#bgpTableBody");
      if (body) body.innerHTML = `<tr><td colspan="8" style="padding:14px;opacity:.75">Sem séries no datasource.</td></tr>`;
      setText("#peersCount", "0 peers");
      setText("#rowsHint", "0 linhas");
      setText("#tableCount", "0 linhas");
      setText("#kpiTotal", 0);
      setText("#kpiUp", 0);
      setText("#kpiAl", 0);
      setText("#kpiNoPfx", 0);
      setText("#lastUpdate", "Atualizado: -");
      const topBody = q("#topBody");
      if (topBody) topBody.innerHTML = "";
      const pgInfo = q("#pgInfo");
      if (pgInfo) pgInfo.textContent = "Página 0/0";
      return;
    }

    // ========= última atualização =========
    {
      let maxTs = null;
      for (const s of series) {
        const ts = getLastTimestamp(s);
        if (ts !== null && (maxTs === null || ts > maxTs)) maxTs = ts;
      }
      if (maxTs !== null) {
        const d = new Date(maxTs);
        const hh = String(d.getHours()).padStart(2, "0");
        const mm = String(d.getMinutes()).padStart(2, "0");
        const ss = String(d.getSeconds()).padStart(2, "0");
        setText("#lastUpdate", `Atualizado: ${hh}:${mm}:${ss}`);
      } else {
        setText("#lastUpdate", "Atualizado: -");
      }
    }

    // ========= monta sessões =========
    const stateSeriesBySessKey = new Map();  // key completa
const stateSeriesByBaseKey = new Map();  // key base (sem client/asn)
const uptimeSeriesBySessKey = new Map(); // key completa
const uptimeSeriesByBaseKey = new Map(); // key base (sem client/asn)
const sessMap = new Map();


    for (const s of series) {
      const host = extractHost(s);
      const p = parseName(safeStr(s?.name || ""));
      const last = getLastValue(s);

const baseKey = `${p.vrf}||${p.peer}||${p.ipver}||${host}`;
const key = `${baseKey}||${p.client}||${p.asn}`;
      if (!sessMap.has(key)) {
        sessMap.set(key, {
          host,
          vrf: p.vrf,
          peer: p.peer,
          ipver: p.ipver,
          client: p.client || "-",
          asn: p.asn || "",
          state: "",
          uptime: 0,
          prefixes: 0,
          lastError: ""
        });
      }
      const o = sessMap.get(key);

      if (p.metric === "state") {
        const raw = safeStr(last);
        const n = toNum(raw);
        if (n) {
          o.state =
            (n === 6) ? "ESTABLISHED" :
            (n === 5) ? "OPENCONFIRM" :
            (n === 4) ? "OPENSENT" :
            (n === 3) ? "ACTIVE" :
            (n === 2) ? "CONNECT" :
            (n === 1) ? "IDLE" :
            `STATE_${n}`;
        } else {
          o.state = raw.toUpperCase();
        }
stateSeriesBySessKey.set(key, s);
stateSeriesByBaseKey.set(baseKey, s);
      } else if (p.metric === "uptime") {
        o.uptime = toNum(last);
        uptimeSeriesBySessKey.set(key, s);
        uptimeSeriesByBaseKey.set(baseKey, s);
      } else if (p.metric === "prefixes") {
        o.prefixes = toNum(last);
      } else if (p.metric === "error") {
        o.lastError = safeStr(last);
      }
    }

   const sessions = [...sessMap.entries()].map(([sessKey, s]) => {
  const parts = String(sessKey).split("||");
  const baseKey = parts.slice(0,4).join("||"); // vrf||peer||ipver||host

  return {
    ...s,
    sessKey,
    baseKey,
    state: s.state || "UNKNOWN",
    uptime: toNum(s.uptime),
    prefixes: toNum(s.prefixes),
    ipNum: (s.ipver === "IPv4") ? 4 : (s.ipver === "IPv6") ? 6 : 0
  };
});


    const sessionByKey = new Map(sessions.map(s => [s.sessKey, s]));

    // ========= VRF Pills =========
    const vrfSet = new Set(sessions.map(s => s.vrf).filter(v => v && v !== "-"));
    const vrfs = ["ALL", ...Array.from(vrfSet).sort((a,b)=>a.localeCompare(b))];

    let activeVrf = root.__ispxActiveVrf || "ALL";
    const vrfHost = q("#vrfPills");
    if (vrfHost) {
      vrfHost.innerHTML = vrfs.map(v => `<div class="u-pill ${v===activeVrf?"on":""}" data-vrf="${esc(v)}">${esc(v)}</div>`).join("");

      if (!vrfHost.__ispxVrfBound) {
        vrfHost.addEventListener("click", (e) => {
          const pill = e.target.closest(".u-pill");
          if (!pill) return;
          activeVrf = pill.getAttribute("data-vrf") || "ALL";
          root.__ispxActiveVrf = activeVrf;
          root.__ispxPage = 0;
          qa("#vrfPills .u-pill").forEach(x => x.classList.toggle("on", x.getAttribute("data-vrf") === activeVrf));
          refreshKPIs();
          rebuildGroups();
          renderTop();
          applyFilter();
        });
        vrfHost.__ispxVrfBound = true;
      }
    }

    function vrfFilteredSessions(){
      if (activeVrf === "ALL") return sessions;
      return sessions.filter(s => s.vrf === activeVrf);
    }

    // ========= KPIs =========
    function refreshKPIs() {
      const list = vrfFilteredSessions();
      const total = list.length;
      const up = list.filter(x => x.state === "ESTABLISHED").length;
      const al = total - up;
      const nop = list.filter(x => x.state === "ESTABLISHED" && x.prefixes === 0).length;

      setText("#kpiTotal", total);
      setText("#kpiUp", up);
      setText("#kpiAl", al);
      setText("#kpiNoPfx", nop);
      setText("#peersCount", `${total} peers`);
    }


// ========= FLAPS (STATE + UPTIME) — RANGE ATUAL (sem persistência) =========
// Ideia: casar STATE (v4/v6) com UPTIME (v4/v6) para detectar quedas e resets
// de forma mais linear, evitando falso positivo de itens recém-criados e evitando
// cache/localStorage travando o painel.

function _validState(x){
  const n = Number(x);
  if (!Number.isFinite(n)) return null;
  const i = Math.round(n);
  if (i < 1 || i > 6) return null;
  return i;
}
function _validUptime(x){
  const n = Number(x);
  return Number.isFinite(n) && n >= 0 ? n : null;
}

function buildFlapFromStateAndUptime(stateSer, upSer){
  const st = stateSer ? extractTimeValueArrays(stateSer) : { times: [], values: [] };
  const up = upSer ? extractTimeValueArrays(upSer) : { times: [], values: [] };

  const stPts = [];
  for (let i = 0; i < (st.times || []).length; i++){
    const t = normTs(st.times[i]);
    const v = _validState((st.values || [])[i]);
    if (Number.isFinite(t) && v !== null) stPts.push({ t, v });
  }
  const upPts = [];
  for (let i = 0; i < (up.times || []).length; i++){
    const t = normTs(up.times[i]);
    const v = _validUptime((up.values || [])[i]);
    if (Number.isFinite(t) && v !== null) upPts.push({ t, v });
  }

  // Se não tem praticamente nada, não inventa histórico.
  if (stPts.length < 2 && upPts.length < 2){
    return { insufficient: true, count: 0, events: [] };
  }

  // timeline combinada (step-wise / last-known)
  const tSet = new Set();
  for (const p of stPts) tSet.add(p.t);
  for (const p of upPts) tSet.add(p.t);
  const timeline = Array.from(tSet).sort((a,b)=>a-b);

  let si = 0, ui = 0;
  let curState = null;
  let curUp = null;
  let prevUp = null;

  let seenEstablished = false;

  let wasUp = false;
  const events = [];

  const openDown = (t, stVal) => {
    events.push({ start: t, end: null, state: (stVal === null ? -1 : stVal) });
  };
  const closeDown = (t) => {
    for (let j = events.length - 1; j >= 0; j--){
      if (events[j] && events[j].end === null){
        events[j].end = t;
        break;
      }
    }
  };

  for (let k = 0; k < timeline.length; k++){
    const t = timeline[k];

    while (si < stPts.length && stPts[si].t <= t){ curState = stPts[si].v; si++; }
    while (ui < upPts.length && upPts[ui].t <= t){ curUp = upPts[ui].v; ui++; }

    if (curState === 6) seenEstablished = true;

    // "UP" = state==6 e (uptime inexistente OU >0). Uptime 0/NULL enquanto established pode acontecer em bordas,
    // mas aqui tratamos 0 como "não-up" pra casar com reset/queda.
    const isUp = (curState === 6) && (curUp === null || curUp > 0);

    // RESET: state ainda 6 mas uptime voltou pra baixo (reinício de sessão)
    if (curState === 6 && prevUp !== null && curUp !== null){
      if (curUp + 5 < prevUp) {
        // evento instantâneo "RESET" (state=0), não abre DOWN prolongado
        events.push({ start: t, end: t, state: 0 });
      }
    }

    // DOWN start: estava UP e deixou de estar UP
    if (wasUp && !isUp){
      openDown(t, curState);
    }

    // DOWN end: estava DOWN e voltou a UP
    if (!wasUp && isUp){
      closeDown(t);
    }

    wasUp = isUp;

    if (curUp !== null) prevUp = curUp;
  }

  // Anti-falso-positivo: se nunca viu ESTABLISHED no range, não dá pra afirmar "queda"
  if (!seenEstablished){
    return { insufficient: true, count: 0, events: [] };
  }

  // Mantém só eventos válidos (start definido)
  const clean = events.filter(ev => ev && Number.isFinite(ev.start));

  return { insufficient: false, count: clean.length, events: clean };
}

// cache por render (evita recomputar 100x na tabela)
const flapCache = root.__ispxFlapCache || (root.__ispxFlapCache = new Map());
flapCache.clear();

function getStableFlapKey(sessKey){
  const ss = sessionByKey.get(sessKey);
  return (ss && ss.baseKey) ? ss.baseKey : sessKey;
}

function getFlapInfo(sessKey){
  const stableKey = getStableFlapKey(sessKey);
  if (flapCache.has(stableKey)) return flapCache.get(stableKey);

  const ss = sessionByKey.get(sessKey);

  // Preferir séries por baseKey (mais estável)
  let stSer = null;
  let upSer = null;

  if (ss && ss.baseKey){
    stSer = stateSeriesByBaseKey.get(ss.baseKey) || null;
    upSer = uptimeSeriesByBaseKey.get(ss.baseKey) || null;
  }
  if (!stSer) stSer = stateSeriesBySessKey.get(sessKey) || null;
  if (!upSer) upSer = uptimeSeriesBySessKey.get(sessKey) || null;

  const r = buildFlapFromStateAndUptime(stSer, upSer);
  flapCache.set(stableKey, r);
  return r;
}

function aggByClient(list) {
      const m = new Map();
      for (const s of list) {
        const client = (s.client && s.client !== "-") ? s.client : "(Sem nome)";
        const asn = s.asn ? s.asn : "-";
        const k = `${client}||${asn}`;
        if (!m.has(k)) m.set(k, { client, asn, sessions:0, established:0, prefixes:0 });
        const a = m.get(k);
        a.sessions++;
        if (s.state === "ESTABLISHED") a.established++;
        a.prefixes += toNum(s.prefixes);
      }
      return [...m.values()];
    }

    // ========= TOP CLIENTES =========
    let scope = root.__ispxTopScope || "sessions"; // sessions | established | prefixes | flaps

    function buildClientFlapDetailsHTML(clientName, asn){
      const list = vrfFilteredSessions().filter(s => {
        const c = (s.client && s.client !== "-") ? s.client : "(Sem nome)";
        const a = s.asn ? s.asn : "-";
        return c === clientName && a === asn;
      });

      const rows = [];
      for (const s of list){
        const info = getFlapInfo(s.sessKey);
        const flaps = toNum(info.count);
        if (flaps > 0) rows.push({ ipver: s.ipver, peer: s.peer, flaps });
      }

      rows.sort((a,b)=> (b.flaps - a.flaps) || safeStr(a.peer).localeCompare(safeStr(b.peer)));

      if (!rows.length){
        return `<div style="opacity:.75;padding:6px">Nenhum peer com queda detectada no range atual.</div>`;
      }

      return `
        <div class="u-flapbox">
          <div style="display:flex;justify-content:space-between;align-items:center;margin-bottom:6px;font-size:12px;opacity:.85">
            <div><b>${esc(clientName)}</b> <span style="opacity:.7">• AS${esc(asn)}</span></div>
            <div style="opacity:.75">${rows.length} peers</div>
          </div>
          <table style="width:100%;border-collapse:collapse;font-size:12px">
            <thead>
              <tr>
                <th style="text-align:left;padding:6px;opacity:.7">Peer</th>
                <th style="text-align:right;padding:6px;opacity:.7">Quedas</th>
              </tr>
            </thead>
            <tbody>
              ${rows.map(r => `
                <tr>
                  <td style="padding:6px;border-top:1px solid rgba(255,255,255,.06)">
                    <b>${esc(r.ipver)}</b> • ${esc(r.peer)}
                  </td>
                  <td style="padding:6px;border-top:1px solid rgba(255,255,255,.06);text-align:right">
                    <span class="pill pri">${esc(r.flaps)}</span>
                  </td>
                </tr>
              `).join("")}
            </tbody>
          </table>
        </div>
      `;
    }
    // ========= TOP CLIENTES (FLAPS) POPOVER =========
    function __ispxEnsureTopPopover(){
      const id = root.__ispxTopPopId || (root.__ispxTopPopId = "ispx-top-pop-" + Math.random().toString(36).slice(2));
      let el = document.getElementById(id);
      if (!el){
        el = document.createElement("div");
        el.id = id;
        // inline style to beat Grafana stacking contexts
        el.style.cssText = [
          "position:fixed",
          "z-index:2147483647",
          "display:none",
          "min-width:320px",
          "max-width:min(560px, calc(100vw - 24px))",
          "max-height:min(420px, calc(100vh - 120px))",
          "overflow:auto",
          "border-radius:14px",
          "padding:12px",
          "background:rgba(10,25,40,.94)",
          "backdrop-filter:blur(10px)",
          "box-shadow:0 12px 28px rgba(0,0,0,.38)",
          "border:1px solid rgba(255,255,255,.10)",
          "color:rgba(255,255,255,.92)",
          "pointer-events:auto",
          "transform:translateZ(0)"
        ].join(";");
        document.body.appendChild(el);

        // close on outside click
        document.addEventListener("mousedown", (e) => {
          if (el.style.display === "none") return;
          const anchor = root.__ispxTopPopAnchor;
          if (el.contains(e.target)) return;
          if (anchor && anchor.contains && anchor.contains(e.target)) return;
          el.style.display = "none";
          root.__ispxTopOpenKey = null;
        }, { passive:true });

        // close on ESC
        document.addEventListener("keydown", (e) => {
          if (e.key === "Escape"){
            el.style.display = "none";
            root.__ispxTopOpenKey = null;
          }
        });
      }
      return el;
    }

    function __ispxPlaceTopPopover(popEl, anchorEl){
      const a = anchorEl.getBoundingClientRect();
      const margin = 10;

      // show to measure
      popEl.style.display = "block";
      popEl.style.left = "0px";
      popEl.style.top  = "0px";

      const p = popEl.getBoundingClientRect();
      const vw = window.innerWidth;
      const vh = window.innerHeight;

      // align left with the TOP CLIENTES card area (anchor left), clamp
      let left = a.left;
      if (left + p.width > vw - margin) left = vw - margin - p.width;
      if (left < margin) left = margin;

      // prefer down; else up
      const downTop = a.bottom + margin;
      const upTop   = a.top - margin - p.height;
      let top = (downTop + p.height <= vh - margin) ? downTop : upTop;
      if (top < margin) top = margin;

      popEl.style.left = Math.round(left) + "px";
      popEl.style.top  = Math.round(top) + "px";
    }

    function __ispxOpenTopPopover(anchorEl, titleHtml, bodyHtml){
      const pop = __ispxEnsureTopPopover();
      root.__ispxTopPopAnchor = anchorEl;

      pop.innerHTML = `
        <div style="display:flex;align-items:center;justify-content:space-between;gap:10px;margin-bottom:10px">
          <div style="font-weight:800;font-size:13px;white-space:nowrap;overflow:hidden;text-overflow:ellipsis">${titleHtml}</div>
          <button type="button" data-topclose="1"
            style="cursor:pointer;border:0;border-radius:10px;padding:6px 10px;background:rgba(255,255,255,.08);color:rgba(255,255,255,.92)">
            Fechar
          </button>
        </div>
        <div>${bodyHtml}</div>
      `;

      const btn = pop.querySelector('[data-topclose="1"]');
      if (btn){
        btn.addEventListener("click", () => {
          pop.style.display = "none";
          root.__ispxTopOpenKey = null;
        }, { once:true });
      }

      __ispxPlaceTopPopover(pop, anchorEl);
    }



    function renderTop() {
      const list = vrfFilteredSessions();
      // (otimizado) nao pre-calcula flaps para todos os peers a cada refresh;
      // flaps agora sao calculados sob demanda (scope=flaps / modal / detalhes).

      if (scope === "flaps") {
        const byKey = new Map();

        for (const s of list) {
          const fl = toNum(getFlapInfo(s.sessKey).count);
          if (fl <= 0) continue;

          const client = (s.client && s.client !== "-") ? s.client : "(Sem nome)";
          const asn = s.asn ? s.asn : "-";
          const k = `${client}||${asn}`;

          if (!byKey.has(k)) byKey.set(k, { client, asn, sessions:0, flaps:0 });
          const a = byKey.get(k);
          a.sessions++;
          a.flaps += fl;
        }

        const arr = [...byKey.values()]
          .sort((a,b)=> (b.flaps - a.flaps) || (b.sessions - a.sessions));

        const topBody = q("#topBody");
        if (!topBody) return;

        if (!arr.length){
          root.__ispxTopOpenKey = null;
          topBody.innerHTML = `<tr><td style="opacity:.7">Nenhum cliente com quedas</td><td>—</td></tr>`;
          return;
        }

        const openKey = root.__ispxTopOpenKey || null;
        if (openKey && !arr.some(r => `${r.client}||${r.asn}` === openKey)) {
          root.__ispxTopOpenKey = null;
        }

        topBody.innerHTML = arr.slice(0, 10).map(r => {
          const rk = `${r.client}||${r.asn}`;
          return `
            <tr class="top-row" data-topkey="${esc(rk)}" data-client="${esc(r.client)}" data-asn="${esc(r.asn)}">
              <td><b>${esc(r.client)}</b> <span style="opacity:.7">• AS${esc(r.asn)}</span></td>
              <td>${esc(r.flaps)}</td>
            </tr>
          `;
        }).join("");

        if (!topBody.__ispxTopDropBound){
          topBody.addEventListener("click", (e) => {
            const row = e.target.closest("tr.top-row");
            if (!row) return;
            if ((root.__ispxTopScope || "sessions") !== "flaps") return;

            const rk = row.getAttribute("data-topkey");
            const client = row.getAttribute("data-client") || "(Sem nome)";
            const asn = row.getAttribute("data-asn") || "-";
            if (!rk) return;

            // toggle: clicking same client closes
            const pop = __ispxEnsureTopPopover();
            const isSameOpen = (root.__ispxTopOpenKey === rk) && (pop.style.display !== "none");
            if (isSameOpen){
              pop.style.display = "none";
              root.__ispxTopOpenKey = null;
              return;
            }

            const titleHtml = `<b>${esc(client)}</b> <span style="opacity:.7">• AS${esc(asn)}</span>`;
            const bodyHtml  = buildClientFlapDetailsHTML(client, asn);
            __ispxOpenTopPopover(row, titleHtml, bodyHtml);
            root.__ispxTopOpenKey = rk;
          });

          topBody.__ispxTopDropBound = true;
        }

        return;
      }

      const agg = aggByClient(list);
      let arr = agg;
      if (scope === "sessions") arr = [...agg].sort((a,b)=> (b.sessions - a.sessions) || (b.prefixes - a.prefixes));
      else if (scope === "established") arr = [...agg].sort((a,b)=> (b.established - a.established) || (b.sessions - a.sessions));
      else arr = [...agg].sort((a,b)=> (b.prefixes - a.prefixes) || (b.sessions - a.sessions));

      const topBody = q("#topBody");
      if (!topBody) return;

      topBody.innerHTML = arr.slice(0, 10).map(r => {
        const val = (scope === "sessions") ? r.sessions : (scope === "established") ? r.established : r.prefixes;
        return `
          <tr>
            <td><b>${esc(r.client)}</b> <span style="opacity:.7">• AS${esc(r.asn)}</span></td>
            <td>${esc(val)}</td>
          </tr>
        `;
      }).join("") || `<tr><td style="opacity:.7">Sem dados</td><td>—</td></tr>`;
    }

    const scopeBtns = qa("#topScope button");
    if (!root.__ispxTopBound) {
      scopeBtns.forEach(b => {
        b.addEventListener("click", () => {
          scope = b.dataset.scope || "sessions";
          root.__ispxTopScope = scope;
          scopeBtns.forEach(x => x.classList.toggle("on", x === b));
          if (scope !== "flaps") root.__ispxTopOpenKey = null;
          renderTop();
        });
      });
      root.__ispxTopBound = true;
    }
    scopeBtns.forEach(x => x.classList.toggle("on", (x.dataset.scope || "sessions") === scope));

    // ========= MODAL =========
    const modal = q("#modal");
    const modalTitle = q("#modalTitle");
    const modalContent = q("#modalContent");
    const modalClose = q("#modalClose");

    function openModal(title, html){
      if (!modal) return;
      if (modalTitle) modalTitle.textContent = title || "Detalhes";
      if (modalContent) modalContent.innerHTML = html || "";
      modal.classList.add("on");
    }
    function closeModal(){
      if (!modal) return;
      modal.classList.remove("on");
    }

    if (modalClose && !modalClose.__bound){
      modalClose.addEventListener("click", (e)=>{ e.preventDefault(); closeModal(); });
      modalClose.__bound = true;
    }
    if (modal && !modal.__bound){
      modal.addEventListener("click", (e)=>{ if (e.target === modal) closeModal(); });
      modal.__bound = true;
    }

    // ========= CACHE PRINCIPAL =========
    const detailsCache = root.__ispxDetailsCache || (root.__ispxDetailsCache = new Map());
    const groupByKey = root.__ispxGroupByKey || (root.__ispxGroupByKey = new Map());
    let groupArrAll = [];

    function summarizeGroup(arr) {
      let total = arr.length, up = 0, al = 0, nop = 0;
      for (const x of arr) {
        if (x.state === "ESTABLISHED") up++;
        else al++;
        if (x.state === "ESTABLISHED" && toNum(x.prefixes) === 0) nop++;
      }
      return { total, up, al, nop };
    }

    function rebuildGroups() {
      const groups = new Map();
      for (const s of vrfFilteredSessions()) {
        const client = (s.client && s.client.trim()) ? s.client : "-";
        const asn = s.asn ? s.asn : "-";
        const host = s.host || "-";
        const gk = [client, asn, host].join("||");
        if (!groups.has(gk)) groups.set(gk, []);
        groups.get(gk).push(s);
      }

      groupArrAll = [...groups.entries()].map(([k, arr]) => {
        const [client, asn, host] = k.split("||");
        const sum = summarizeGroup(arr);
        return { key:k, client, asn, host, sum, items: arr };
      });

      groupArrAll.sort((a,b) => (b.sum.al - a.sum.al) || (b.sum.total - a.sum.total) || a.client.localeCompare(b.client));

      detailsCache.clear();
      groupByKey.clear();
      for (const g of groupArrAll) groupByKey.set(g.key, g);
    }

    rebuildGroups();

    // ========= sort =========
    const sortState = root.__ispxSort || (root.__ispxSort = { col: "alert", dir: "desc" });

    function applySortHeaderUI() {
      qa(".u-table thead th.sortable").forEach(th => {
        th.classList.remove("sort-asc", "sort-desc");
        const col = th.getAttribute("data-col");
        if (col && col === sortState.col) th.classList.add(sortState.dir === "asc" ? "sort-asc" : "sort-desc");
      });
    }

    const thead = q(".u-table thead");
    if (thead && !thead.__ispxSortBound) {
      thead.addEventListener("click", (e) => {
        const th = e.target.closest("th.sortable");
        if (!th) return;
        const col = th.getAttribute("data-col");
        if (!col) return;

        if (sortState.col === col) sortState.dir = (sortState.dir === "asc") ? "desc" : "asc";
        else { sortState.col = col; sortState.dir = "desc"; }

        root.__ispxSort = sortState;
        applySortHeaderUI();
        root.__ispxPage = 0;
        closeAll();
        applyFilter(false);
      });
      thead.__ispxSortBound = true;
    }
    applySortHeaderUI();

    function sortRows(rows) {
      const dir = (sortState.dir === "asc") ? 1 : -1;
      const col = sortState.col;

      const cmpStr = (a,b) => String(a||"").localeCompare(String(b||""), undefined, { sensitivity: "base" });
      const cmpNum = (a,b) => (toNum(a) - toNum(b));

      const getVal = (r) => {
        if (col === "client") return r.client;
        if (col === "asn") return r.asn;
        if (col === "host") return r.host;
        if (col === "sessions") return r.sum.total;
        if (col === "up") return r.sum.up;
        if (col === "alert") return r.sum.al;
        if (col === "nopfx") return r.sum.nop;
        return r.sum.al;
      };

      const isNumeric = (col === "sessions" || col === "up" || col === "alert" || col === "nopfx" || col === "asn");

      return [...rows].sort((ra, rb) => {
        const va = getVal(ra);
        const vb = getVal(rb);
        const base = isNumeric ? cmpNum(va, vb) : cmpStr(va, vb);
        if (base) return base * dir;
        return ((rb.sum.al - ra.sum.al) || (rb.sum.total - ra.sum.total) || cmpStr(ra.client, rb.client));
      });
    }

    function buildChildTbodyHTML(lines){
  return lines.map(s => {
    const st = safeStr(s.state);
    const cls = (st === "ESTABLISHED") ? "good" : (st === "ACTIVE" || st === "CONNECT") ? "warn" : "bad";
    const hasHist = true;

    const pfx = toNum(s.prefixes);

    return `
      <tr>
        <td><b>${esc(s.ipver)}</b></td>
        <td>${esc(s.vrf)}</td>
        <td>${esc(s.peer)}</td>
        <td><span class="pill ${cls}">${esc(st || "-")}</span></td>
        <td>${esc(fmtUptime(s.uptime))}</td>
        <td title="${esc(pfx.toLocaleString('pt-BR'))}">${esc(fmtPrefixes(pfx))}</td>
        <td>
          <div class="le-wrap">
            <span>${esc(s.lastError || "-")}</span>
            ${(() => {
              const tip = explainLastError(s.lastError || "-");
              return tip ? `<span class="le-help" data-tip="${esc(tip)}" title="${esc(tip)}">?</span>` : "";
            })()}
          </div>
        </td>
        <td class="center">
          ${hasHist ? `<button class="u-hbtn" data-hist="${esc(s.sessKey)}" title="Ver histórico de quedas">Hist</button>` : `<span style="opacity:.55">—</span>`}
        </td>
      </tr>
    `;
  }).join("");
}


    function closeAll() {
      qa(".u-child").forEach(tr => tr.style.display = "none");
      qa(".u-exp").forEach(b => b.setAttribute("aria-expanded", "false"));
      root.__ispxOpenKey = null;
    }

    function toggle(key) {
      const btn   = q(`.u-exp[data-child="${CSS.escape(key)}"]`);
      const child = q(`.u-child[data-child="${CSS.escape(key)}"]`);
      if (!btn || !child) return;

      const isOpen = btn.getAttribute("aria-expanded") === "true";

      if (root.__ispxOpenKey && root.__ispxOpenKey !== key) {
        const oldKey = root.__ispxOpenKey;
        const oldBtn = q(`.u-exp[data-child="${CSS.escape(oldKey)}"]`);
        const oldCh  = q(`.u-child[data-child="${CSS.escape(oldKey)}"]`);
        if (oldBtn) oldBtn.setAttribute("aria-expanded", "false");
        if (oldCh)  oldCh.style.display = "none";
      }

      if (isOpen) {
        btn.setAttribute("aria-expanded", "false");
        child.style.display = "none";
        root.__ispxOpenKey = null;
        return;
      }

      if (!detailsCache.has(key)) {
        const g = groupByKey.get(key);
        const lines = (g?.items || []).slice().sort((a,b)=>
          String(a.ipver).localeCompare(String(b.ipver)) || String(a.peer).localeCompare(String(b.peer))
        );
        detailsCache.set(key, buildChildTbodyHTML(lines));
      }

      const tbody = q(`tbody[data-childtbody="${CSS.escape(key)}"]`);
      if (tbody) tbody.innerHTML = detailsCache.get(key);

      btn.setAttribute("aria-expanded", "true");
      child.style.display = "table-row";
      root.__ispxOpenKey = key;
    }

    function render(rows) {
      const body = q("#bgpTableBody");
      if (!body) return;

      body.innerHTML = rows.map(r => `
        <tr class="u-row" data-childkey="${esc(r.key)}" data-key="${esc(r.client)} ${esc(r.asn)} ${esc(r.host)}">
          <td class="client">${esc(r.client)}</td>
          <td>${esc(r.asn)}</td>
          <td>${esc(r.host)}</td>
          <td class="center"><span class="pill pri">${r.sum.total}</span></td>
          <td class="center"><span class="pill good">${r.sum.up}</span></td>
          <td class="center"><span class="pill bad">${r.sum.al}</span></td>
          <td class="center"><span class="pill warn">${r.sum.nop}</span></td>
          <td class="center">
            <button class="u-exp" aria-expanded="false" data-child="${esc(r.key)}" title="Expandir">
              <span class="arrow">▶</span>
            </button>
          </td>
        </tr>

        <tr class="u-child" data-child="${esc(r.key)}" style="display:none">
          <td colspan="8">
            <div class="child-wrap">
              <table class="u-mini-sub">
                <thead>
                  <tr>
                    <th style="width:7%">IPVER</th>
                    <th style="width:12%">VRF</th>
                    <th style="width:24%">PEER</th>
                    <th style="width:12%">STATUS</th>
                    <th style="width:14%">UPTIME</th>
                    <th style="width:12%">TOTAL PREFIX</th>
                    <th>LAST ERROR</th>
                    <th style="width:7%">HIST</th>
                  </tr>
                </thead>
                <tbody data-childtbody="${esc(r.key)}">
                  <tr><td colspan="8" style="padding:10px;opacity:.7">Clique para carregar…</td></tr>
                </tbody>
              </table>
            </div>
          </td>
        </tr>
      `).join("");
    }

    // ========= PAGINAÇÃO =========
    const pgPrev = q("#pgPrev");
    const pgNext = q("#pgNext");
    const pgInfo = q("#pgInfo");
    const pgSize = q("#pgSize");

    let pageSize = toNum(root.__ispxPageSize) || 15;
    let page = toNum(root.__ispxPage) || 0;

    if (pgSize && !pgSize.__bound) {
      pgSize.value = String(pageSize);
      pgSize.addEventListener("change", () => {
        root.__ispxPageSize = toNum(pgSize.value) || 25;
        root.__ispxPage = 0;
        closeAll();
        applyFilter();
      });
      pgSize.__bound = true;
    } else if (pgSize) {
      pgSize.value = String(pageSize);
    }

    function setPager(totalRows){
      pageSize = toNum(root.__ispxPageSize) || pageSize || 25;
      page = toNum(root.__ispxPage) || 0;

      const totalPages = Math.max(1, Math.ceil(totalRows / pageSize));
      page = Math.max(0, Math.min(page, totalPages - 1));
      root.__ispxPage = page;

      if (pgInfo) pgInfo.textContent = `Página ${page+1}/${totalPages} • ${totalRows} linhas`;
      if (pgPrev) pgPrev.disabled = (page <= 0);
      if (pgNext) pgNext.disabled = (page >= totalPages - 1);

      if (pgPrev && !pgPrev.__bound) {
        pgPrev.addEventListener("click", () => {
          root.__ispxPage = Math.max(0, (toNum(root.__ispxPage)||0) - 1);
          closeAll();
          applyFilter(false);
        });
        pgPrev.__bound = true;
      }
      if (pgNext && !pgNext.__bound) {
        pgNext.addEventListener("click", () => {
          root.__ispxPage = (toNum(root.__ispxPage)||0) + 1;
          closeAll();
          applyFilter(false);
        });
        pgNext.__bound = true;
      }

      return { totalPages, page, pageSize };
    }

    // ========= Delegação de clique =========
    const clickHost = q(".u-table-scroll") || root;
    if (clickHost.__ispxClickHandler) clickHost.removeEventListener("click", clickHost.__ispxClickHandler, true);

    clickHost.__ispxClickHandler = (e) => {
      const histBtn = e.target.closest(".u-hbtn");
      if (histBtn) {
        e.preventDefault();
        e.stopPropagation();
        const sessKey = histBtn.getAttribute("data-hist");
        const s = sessKey ? sessionByKey.get(sessKey) : null;
        const info = sessKey ? getFlapInfo(sessKey) : { count:0, events:[], insufficient:true };

        if (!s) {
          openModal("Histórico de quedas", `<div style="opacity:.75;padding:8px">Sem dados para este peer.</div>`);
          return;
        }

        if (info.insufficient) {
          openModal(
            `Histórico de quedas — ${esc(s.client)} • AS${esc(s.asn||"-")}`,
            `<div style="opacity:.75;padding:8px">
              Este peer <b>não ficou ESTABLISHED (6)</b> em nenhum ponto dentro do range atual, então <b>não é possível afirmar quedas</b> por transição 6→≠6.<br>
              (Ele pode estar permanentemente em CONNECT/ACTIVE por configuração, bloqueio, rota/ACL, etc.)
            </div>`
          );
          return;
        }

        if (!info.events || !info.events.length) {
          openModal(
            `Histórico de quedas — ${esc(s.client)} • AS${esc(s.asn||"-")}`,
            `<div style="opacity:.75;padding:8px">Nenhuma queda detectada no intervalo atual.</div>`
          );
          return;
        }

        const rows = info.events.slice().sort((a,b)=> (b.start - a.start)).slice(0, 200).map(ev => {
          const stName = stateNumToName(toNum(ev.state));
          const start = fmtDT(ev.start);
          const end = ev.end ? fmtDT(ev.end) : "(ainda DOWN)";
          const dur = ev.end ? fmtUptime(Math.max(0, Math.floor((normTs(ev.end) - normTs(ev.start))/1000))) : "—";
          return `<tr>
            <td>${esc(start)}</td>
            <td>${esc(end)}</td>
            <td>${esc(dur)}</td>
            <td><span class="pill ${(stName==="ESTABLISHED")?"good":"bad"}">${esc(stName)}</span></td>
          </tr>`;
        }).join("");

        const html = `
          <div style="opacity:.8;margin-bottom:8px">
            <b>${esc(s.ipver)}</b> • VRF <b>${esc(s.vrf)}</b> • Peer <b>${esc(s.peer)}</b><br>
            Quedas detectadas: <b>${esc(info.count)}</b> (limite de exibição: 200)
          </div>
          <table class="u-top" style="width:100%">
            <thead><tr><th>Início</th><th>Fim</th><th>Duração</th><th>Estado</th></tr></thead>
            <tbody>${rows}</tbody>
          </table>
        `;
        openModal(`Histórico de quedas — ${esc(s.client)} • AS${esc(s.asn||"-")}`, html);
        return;
      }

      const expBtn = e.target.closest(".u-exp");
      if (expBtn) {
        e.preventDefault();
        e.stopPropagation();
        const key = expBtn.getAttribute("data-child");
        if (key) toggle(key);
        return;
      }

      const row = e.target.closest("tr.u-row");
      if (row) {
        const key = row.getAttribute("data-childkey");
        if (key) toggle(key);
      }
    };
    clickHost.addEventListener("click", clickHost.__ispxClickHandler, true);

    const inp = q("#search");

    function applyFilter(resetPage = true) {
      const term = safeStr(inp?.value).toLowerCase().trim();

      let rows = groupArrAll;
      if (term) rows = rows.filter(r => (`${r.client} ${r.asn} ${r.host}`.toLowerCase().includes(term)));

      rows = sortRows(rows);
      if (resetPage) root.__ispxPage = 0;

      const pager = setPager(rows.length);
      const start = pager.page * pager.pageSize;
      const pageRows = rows.slice(start, start + pager.pageSize);

      render(pageRows);

      if (root.__ispxOpenKey) requestAnimationFrame(() => toggle(root.__ispxOpenKey));

      setText("#rowsHint", `${rows.length} linhas`);
      setText("#tableCount", `${rows.length} linhas`);
    }

    if (inp) {
      if (inp.__ispxInputHandler) inp.removeEventListener("input", inp.__ispxInputHandler);
      let t = 0;
      inp.__ispxInputHandler = () => { clearTimeout(t); t = setTimeout(() => applyFilter(true), 150); };
      inp.addEventListener("input", inp.__ispxInputHandler);
    }

    // ========= start =========
    refreshKPIs();
    renderTop();
    applyFilter(false);

    // ========= tooltip flutuante LAST ERROR =========
    (function enableFloatingLastErrorTooltip(){
      if (window.__ispxLeFloatTipBound) return;
      window.__ispxLeFloatTipBound = true;

      let tip = document.querySelector(".le-float-tip");
      let arrow = document.querySelector(".le-float-arrow");

      if (!tip) {
        tip = document.createElement("div");
        tip.className = "le-float-tip";
        tip.style.display = "none";
        document.body.appendChild(tip);
      }
      if (!arrow) {
        arrow = document.createElement("div");
        arrow.className = "le-float-arrow";
        arrow.style.display = "none";
        document.body.appendChild(arrow);
      }

      const clamp = (v, a, b) => Math.max(a, Math.min(b, v));
      let lastEl = null;

      function showFor(el){
        const text = el?.getAttribute?.("data-tip") || el?.getAttribute?.("title") || "";
        if (!text) return;

        lastEl = el;
        tip.textContent = text;

        tip.style.display = "block";
        arrow.style.display = "block";

        tip.classList.remove("is-on");
        arrow.classList.remove("is-on");

        const r = el.getBoundingClientRect();
        const pad = 10;

        const tw = tip.offsetWidth || 260;
        const th = tip.offsetHeight || 60;

        const vw = window.innerWidth;
        const vh = window.innerHeight;

        const preferTop = (r.top > th + 18);
        const top = preferTop ? (r.top - th - 14) : (r.bottom + 14);

        let left = r.left + (r.width / 2) - (tw / 2);
        left = clamp(left, pad, vw - tw - pad);

        tip.style.top = `${clamp(top, pad, vh - th - pad)}px`;
        tip.style.left = `${left}px`;

        const ax = clamp(r.left + r.width/2 - 5, pad, vw - 10 - pad);
        const ay = preferTop ? (r.top - 9) : (r.bottom + 5);

        arrow.style.left = `${ax}px`;
        arrow.style.top = `${clamp(ay, pad, vh - 10 - pad)}px`;

        requestAnimationFrame(() => {
          tip.classList.add("is-on");
          arrow.classList.add("is-on");
        });
      }

      function hide(){
        lastEl = null;
        tip.classList.remove("is-on");
        arrow.classList.remove("is-on");
        setTimeout(() => {
          tip.style.display = "none";
          arrow.style.display = "none";
        }, 80);
      }

      const onOver = (e) => {
        const el = e.target && e.target.closest ? e.target.closest(".le-help") : null;
        if (!el) return;
        showFor(el);
      };
      const onOut = (e) => {
        const el = e.target && e.target.closest ? e.target.closest(".le-help") : null;
        if (!el) return;
        hide();
      };

      document.addEventListener("pointerover", onOver, { passive: true, capture: true });
      document.addEventListener("pointerout", onOut, { passive: true, capture: true });
      // (otimizado) remove listeners duplicados de mouseover/mouseout; pointer events ja cobrem.
      window.addEventListener("scroll", hide, { passive: true, capture: true });
      window.addEventListener("resize", hide, { passive: true });
      // (otimizado) removido MutationObserver (custo extra).
    })();

  } catch (e) {
    console.error("onRender error:", e);
    throw e;
  }
})();
